import { Col, Form, Input, InputNumber, Radio, Row, Select, Spin } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import { SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import Contacts from "src/services/Contacts"

const ModalAddGroups = ({ open, onCancel, onOk, Type, text, isEdit }) => {
  const [form] = Form.useForm()
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [loading, setLoading] = useState(false)

  const handleSubmit = () => {
    form.validateFields().then(values => {
      setLoading(true)
      Contacts[isEdit ? "updateGroupAccount" : "insertGroupAccount"]({
        ...values,
        GroupID: isEdit && isEdit.GroupID,
        Type: Type === 7 ? values.Type : 0,
      })
        .then(res => {
          if (res.isOk) {
            Notice({ msg: `${isEdit ? "Cập nhật" : "Thêm mới"} thành công.` })
            onCancel()
            onOk()
          }
        })
        .finally(() => setLoading(false))
    })
  }

  useEffect(() => {
    if (isEdit) return form.setFieldsValue(isEdit)
    form.setFieldsValue({
      Status: 1,
      Type: 3,
    })
  }, [isEdit, form])

  const renderFooter = () => (
    <div className="d-flex-end">
      <Button
        btnType="primary"
        className="btn-hover-shadow"
        onClick={handleSubmit}
      >
        Ghi lại
      </Button>
    </div>
  )

  return (
    <CustomModal
      title={`${isEdit ? "Cập nhật" : "Thêm"} ${text}`}
      open={open}
      width="900px"
      onCancel={onCancel}
      footer={renderFooter()}
    >
      <Spin spinning={loading}>
        <Form form={form} layout="vertical">
          <Row gutter={16}>
            {Type === 7 && (
              <Col span={24}>
                <Form.Item
                  label="Loại đơn vị"
                  name="Type"
                  rules={[
                    {
                      required: true,
                      message: "Thông tin không được để trống",
                    },
                  ]}
                >
                  <Radio.Group>
                    {getListComboByKey(
                      SYSTEM_KEY.UNIT_TYPE,
                      listSystemKey,
                    )?.map(i => (
                      <Radio value={+i.CodeValue} key={+i.CodeValue}>
                        {i.Description}
                      </Radio>
                    ))}
                    {/* <Radio value={3}>Công đoàn cơ sở trực thuộc</Radio>
                    <Radio value={4}>Công đoàn y tế tỉnh thành</Radio> */}
                  </Radio.Group>
                </Form.Item>
              </Col>
            )}
            <Col span={24}>
              <Form.Item
                label={`Tên ${text}`}
                name="GroupName"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <Input placeholder={`Nhập tên ${text}`} />
              </Form.Item>
            </Col>
            <Col span={14}>
              <Form.Item label="Trạng thái" name="Status">
                <Select placeholder="chọn trạng thái">
                  {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(
                    i => (
                      <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                        {i?.Description}
                      </Select.Option>
                    ),
                  )}
                </Select>
              </Form.Item>
            </Col>
            <Col span={10}>
              <Form.Item label="Thứ tự" name="SortOrder">
                <InputNumber
                  placeholder="Nhập số"
                  className="ant-input-number_no_arrow"
                />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Spin>
    </CustomModal>
  )
}

export default ModalAddGroups
