import { Button, Spin } from "antd"
import { useEffect, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import CustomModal from "src/components/Modal/CustomModal"
import Notice from "src/components/Notice"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import { COLOR_STATUS, hideOnSinglePage } from "src/constants/constants"
import ContactService from "src/services/Contacts"

const ModalAddMemberToGroup = ({ open, onCancel, onOk, GroupID }) => {
  const [pagination, setPagination] = useState({
    PageSize: 10,
    CurrentPage: 1,
    Status: 1,
  })
  const [listData, setListData] = useState([])
  const [listSelect, setListSelect] = useState([])
  const [loading, setLoading] = useState(false)
  const [TextSearch, setTextSearch] = useState("")

  const handleSubmit = () => {
    setLoading(true)
    ContactService.insertMemberToGroup({
      GroupID: GroupID,
      UserID: listSelect.map(member => member.UserID),
    })
      .then(res => {
        if (res.isOk) {
          Notice({ msg: "Thêm nhân viên thành công." })
          onCancel()
          onOk()
        }
      })
      .finally(() => setLoading(false))
  }
  const getListMemberForGroup = () => {
    setLoading(true)
    ContactService.getListMemberForGroup({
      TextSearch: TextSearch,
      GroupID: GroupID,
    })
      .then(res => {
        if (res.isOk) {
          setListData(res?.Object)
        }
      })
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    if (GroupID) {
      setLoading(true)
      setTextSearch("")
      ContactService.getListMemberForGroup({
        TextSearch: "",
        GroupID: GroupID,
      })
        .then(res => {
          if (res.isOk) {
            setListData(res?.Object)
            setListSelect(res?.Object.filter(i => i?.IsInGroup === 1))
          }
        })
        .finally(() => setLoading(false))
    }
  }, [GroupID])

  const renderFooter = () => (
    <div className="d-flex-end">
      <Button
        btnType="primary"
        className="btn-hover-shadow"
        onClick={handleSubmit}
      >
        Ghi lại
      </Button>
    </div>
  )

  const columns = [
    {
      title: "STT",
      key: "Index",
      width: 60,
      align: "center",
      render: (val, record, idx) => idx + 1,
    },
    {
      title: (
        <>
          <MainTableHeader>Tên đăng nhập</MainTableHeader>
          <SubTableHeader>Họ và tên</SubTableHeader>
        </>
      ),
      dataIndex: "UserName",
      key: "UserName",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{val}</MainTableData>
          <SubTableData>{record?.FullName}</SubTableData>
        </>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Email</MainTableHeader>
          <SubTableHeader>Số điện thoại</SubTableHeader>
        </>
      ),
      dataIndex: "PhoneNumber",
      key: "PhoneNumber",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{record?.Email}</MainTableData>
          <SubTableData>{val}</SubTableData>
        </>
      ),
    },
    {
      title: "Đơn vị",
      key: "AccountName",
      dataIndex: "AccountName",
      render: val => (
        <div className="max-line2" title={val}>
          {val}
        </div>
      ),
    },
    {
      title: "Chức vụ",
      key: "PositionName",
      dataIndex: "PositionName",
      render: val => (
        <div className="max-line2" title={val}>
          {val}
        </div>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: `Status`,
      align: "center",
      width: 140,
      render: (val, record) => (
        <div
          className="fw-700 text-center"
          style={
            val === 1
              ? { color: COLOR_STATUS.active }
              : { color: COLOR_STATUS.inactive }
          }
        >
          {val === 1 ? "Kích hoạt" : "Vô hiệu"}
        </div>
      ),
    },
  ]

  return (
    <CustomModal
      title={"Thêm nhân viên vào nhóm"}
      open={open}
      width="1200px"
      onCancel={onCancel}
      footer={renderFooter()}
    >
      <Spin spinning={loading}>
        <InputCustom
          type="search"
          allowClear
          label="Nhập tìm kiếm"
          className="mb-16"
          onSearch={() => {
            getListMemberForGroup()
            setPagination(pre => ({ ...pre, CurrentPage: 1 }))
          }}
          onChange={e => setTextSearch(e?.target?.value)}
        />
        <TableCustom
          isPrimary
          rowSelection={{
            type: "checkbox",
            selectedRowKeys: listSelect?.map(i => i?.UserID),
            onChange: (listKey, listItems) => {
              setListSelect(listItems)
            },
            preserveSelectedRowKeys: true,
          }}
          dataSource={listData}
          columns={columns}
          sticky={{ offsetHeader: "-24px" }}
          textEmpty="Không có thành viên nào chưa thêm vào nhóm."
          pagination={{
            hideOnSinglePage: listData?.total <= hideOnSinglePage,
            current: pagination?.CurrentPage,
            pageSize: pagination?.PageSize,
            responsive: true,
            total: listData?.total,
            locale: { items_per_page: "" },
            showSizeChanger: listData?.total > 10,
            onChange: (CurrentPage, PageSize) => {
              setPagination({
                ...pagination,
                CurrentPage,
                PageSize,
              })
            },
          }}
          rowKey="UserID"
        />
      </Spin>
    </CustomModal>
  )
}

export default ModalAddMemberToGroup
