import { Col, Divider, InputNumber, Row, Select, Space } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputDebounceCustom from "src/components/Input/InputDebounceCustom"
import Delete from "src/components/Modal/Delete"
import ButtonCustom from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  COLOR_STATUS,
  hideOnSinglePage,
  SYSTEM_KEY,
} from "src/constants/constants"
import { getListComboByKey, renderButtonCircle } from "src/lib/utils"
import ContactsService from "src/services/Contacts"
import ModalAddMemberToGroup from "./components/ModalAddMemberToGroup"
import ModalAddGroups from "./components/ModalInsertGroup"
import { GroupUnitContactStyled } from "./styled"

const { Option } = Select
const GroupUnitContacts = () => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
    Status: 1,
  })
  const [textSearch, setTextSearch] = useState("")
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState({})
  const [listSelect, setListSelect] = useState([])
  const [Type, setType] = useState(7)
  const [openInsert, setOpenInsert] = useState(false)
  const [openModalAddMB, setOpenModalAddMB] = useState(false)
  const [isEdit, setIsEdit] = useState(undefined)
  const [openModalDelete, setOpenModalDelete] = useState(undefined)

  useEffect(() => {
    setPagination({
      PageSize: 20,
      CurrentPage: 1,
      Status: 1,
    })
    setIsEdit(undefined)
    setOpenModalDelete(undefined)
    setListSelect([])
  }, [Type])

  useEffect(() => {
    if (pagination) getList()
  }, [pagination])

  const getList = async () => {
    try {
      setLoading(true)
      const res = await ContactsService.getGroupAccount({
        ...pagination,
        Type,
        textSearch,
      })
      if (res?.isError) return
      setListData(res?.Object)
    } finally {
      setLoading(false)
    }
  }
  const changeValueTable = (idx, object) =>
    setListData(pre => ({
      ...pre,
      lstAccountGroupVM: pre?.lstAccountGroupVM?.map((i, index) => {
        if (idx !== index) return i
        return { ...i, ...object }
      }),
    }))

  const deleteGroupAccount = listID => {
    ContactsService.deleteGroupAccount(listID).then(res => {
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Xóa thành công!",
      })
    })
  }

  const columns = [
    {
      title: `Tên ${Type === 7 ? "nhóm đơn vị" : "nhóm thành viên"}`,
      dataIndex: "GroupName",
      key: "GroupName",
    },
    {
      title: `Đơn vị`,
      dataIndex: "Type",
      key: "Type",
      width: 300,
      render: val =>
        val === 3
          ? "Công đoàn cơ sở trực thuộc"
          : val === 4
          ? "Công đoàn y tế tỉnh thành"
          : "",
    },
    {
      title: "Thứ tự",
      dataIndex: "SortOrder",
      key: `SortOrder`,
      align: "center",
      width: 120,
      render: (value, record, idx) => (
        <InputNumber
          className="ant-input-number_no_arrow"
          value={value}
          onChange={event =>
            changeValueTable(idx, {
              SortOrder: event,
            })
          }
        />
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: `Status`,
      align: "center",
      width: 160,
      render: (val, record) => (
        <div>
          <div
            className="fw-700 text-center"
            style={
              val === 1
                ? { color: COLOR_STATUS.active }
                : { color: COLOR_STATUS.inactive }
            }
          >
            {val === 1 ? "Kích hoạt" : "Vô hiệu"}
          </div>
          <FloatActionWrapper size="small" className="float-action__wrapper">
            {listData?.ButtonShow?.IsUpdate &&
              renderButtonCircle(
                "Chỉnh sửa",
                "edit",
                () => {
                  setOpenInsert(true)
                  setIsEdit(record)
                },
                true,
              )}
            {listData?.ButtonShow?.IsDelete &&
              renderButtonCircle(
                "Xoá",
                "bin",
                () => {
                  setOpenModalDelete(record)
                },
                true,
              )}
            {listData?.ButtonShow?.IsUpdate &&
              Type === 0 &&
              renderButtonCircle(
                "Thêm thành viên",
                "signup",
                () => {
                  setOpenModalAddMB(record)
                },
                true,
              )}
          </FloatActionWrapper>
        </div>
      ),
    },
  ]

  const updateOrders = () => {
    let listOrders = {
      Type: 2,
      lstListUpdateSortOrder: listData?.lstAccountGroupVM.map(data => ({
        ID: data?.GroupID,
        SortOrder: data?.SortOrder,
      })),
    }
    ContactsService.updateSortOrder(listOrders).then(res => {
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Cập nhật vị trí thành công!",
      })
    })
  }

  return (
    <GroupUnitContactStyled>
      <Row gutter={[16, 16]}>
        <Col md={14} xs={24}>
          <InputDebounceCustom
            type="search"
            allowClear
            label="Nhập tìm kiếm"
            autoSearch={true}
            value={textSearch}
            onChange={e => setTextSearch(e?.target?.value)}
            onDebouncedChange={() => {
              setPagination(pre => ({ ...pre, CurrentPage: 1 }))
            }}
          />
        </Col>
        <Col lg={4} xs={24}>
          <SelectCustom
            label="Trạng thái"
            defaultValue={1}
            onChange={Status => {
              setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
            }}
          >
            {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
              <Option key={+i.CodeValue} value={+i.CodeValue}>
                {i?.Description}
              </Option>
            ))}
          </SelectCustom>
        </Col>
        <Col lg={6} xs={24}>
          <SelectCustom
            label="Loại nhóm"
            value={Type}
            onChange={Type => {
              setPagination(pre => ({ ...pre, Type, CurrentPage: 1 }))
              setType(Type)
            }}
          >
            <Option key={7} value={7}>
              Nhóm đơn vị
            </Option>
            <Option key={0} value={0}>
              Nhóm thành viên
            </Option>
          </SelectCustom>
        </Col>
      </Row>
      <Divider className="mv-16" />
      <Row gutter={16}>
        <Col style={{ width: 0 }} flex="auto">
          <Row className="title-type-1 justify-content-space-between align-items-center pb-16 pt-0 mb-16">
            <div style={{ fontSize: 24 }}>
              Danh sách {Type === 7 ? "nhóm đơn vị" : "nhóm thành viên"} (
              {listData?.total}) :
            </div>
            <Space>
              {listData?.ButtonShow?.IsInsert && (
                <ButtonCustom
                  btnType="primary"
                  className="btn-hover-shadow"
                  onClick={() => setOpenInsert(true)}
                >
                  Thêm mới
                </ButtonCustom>
              )}
              {listData?.ButtonShow?.IsUpdate && (
                <ButtonCustom btnType="primary" onClick={updateOrders}>
                  Cập nhật vị trí
                </ButtonCustom>
              )}
              {listSelect.length > 0 && (
                <ButtonCustom
                  btnType="primary"
                  className="btn-hover-shadow"
                  onClick={() =>
                    setOpenModalDelete({
                      deleteAll: true,
                      GroupName: "Tất cả nhóm đã chọn",
                      GroupID: listSelect.map(i => i?.GroupID),
                    })
                  }
                >
                  Xóa nhiều
                </ButtonCustom>
              )}
            </Space>
          </Row>
          <TableCustom
            isPrimary
            rowSelection={{
              selectedRowKeys: listSelect?.map(i => i?.GroupID),
              onChange: (listKey, listItems) => {
                setListSelect(listItems)
              },
              preserveSelectedRowKeys: true,
            }}
            dataSource={listData?.lstAccountGroupVM}
            columns={
              Type === 7
                ? columns
                : columns.filter(i => !(i.dataIndex === "AccountName"))
            }
            sticky={{ offsetHeader: 85 }}
            loading={loading}
            textEmpty="Không có nhóm nào."
            pagination={{
              hideOnSinglePage: listData?.total <= hideOnSinglePage,
              current: pagination?.CurrentPage,
              pageSize: pagination?.PageSize,
              responsive: true,
              total: listData?.total,
              locale: { items_per_page: "" },
              showSizeChanger: listData?.total > 10,
              onChange: (CurrentPage, PageSize) => {
                setPagination({
                  ...pagination,
                  CurrentPage,
                  PageSize,
                })
              },
            }}
            rowKey="GroupID"
          />
        </Col>
      </Row>
      {openInsert && (
        <ModalAddGroups
          open={openInsert}
          isEdit={isEdit}
          Type={Type}
          text={Type === 7 ? "nhóm đơn vị" : "nhóm thành viên"}
          onCancel={() => {
            setOpenInsert(false)
            setIsEdit(undefined)
          }}
          onOk={() => {
            setOpenInsert(false)
            setIsEdit(undefined)
            getList()
          }}
        />
      )}
      {!!openModalAddMB && (
        <ModalAddMemberToGroup
          open={!!openModalAddMB}
          GroupID={openModalAddMB?.GroupID}
          onCancel={() => {
            setOpenModalAddMB(false)
          }}
          onOk={getList}
        />
      )}
      {openModalDelete && (
        <Delete
          isOpen={!!openModalDelete}
          content={{
            title: (
              <div className="fw-600 text-center" style={{ fontSize: 16 }}>
                Bạn có chắc chắn muốn xóa "<b>{openModalDelete?.GroupName}</b>"
                không?
              </div>
            ),
          }}
          onOk={() => {
            deleteGroupAccount(
              openModalDelete?.deleteAll
                ? openModalDelete?.GroupID
                : [openModalDelete?.GroupID],
            )
            setOpenModalDelete(undefined)
          }}
          onCancel={() => setOpenModalDelete(undefined)}
        />
      )}
    </GroupUnitContactStyled>
  )
}

export default GroupUnitContacts
